import React, { useEffect, useState } from "react";
import { getCurrentUser } from "../utils/auth";
import "./Internship.css"; 

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [newInternship, setNewInternship] = useState({ title: "", company: "", link: "" });
  const user = getCurrentUser();
  const isAdmin = user?.role === "admin";
  const isHR = user?.role === "hr";

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(data);
  }, []);

  const handleAdd = () => {
    const updated = [...internships, newInternship];
    localStorage.setItem("internships", JSON.stringify(updated));
    setInternships(updated);
    setNewInternship({ title: "", company: "", link: "" });
  };

  const handleDelete = (index) => {
    const updated = internships.filter((_, i) => i !== index);
    localStorage.setItem("internships", JSON.stringify(updated));
    setInternships(updated);
  };

  const handleEdit = (index, updatedItem) => {
    const updated = [...internships];
    updated[index] = updatedItem;
    localStorage.setItem("internships", JSON.stringify(updated));
    setInternships(updated);
  };

  return (
    <div className="internship-container">
      <h2>Internship Opportunities</h2>

      {(isAdmin || isHR) && (
        <div className="form-section">
          <input
            type="text"
            placeholder="Title"
            value={newInternship.title}
            onChange={(e) => setNewInternship({ ...newInternship, title: e.target.value })}
          />
          <input
            type="text"
            placeholder="Company"
            value={newInternship.company}
            onChange={(e) => setNewInternship({ ...newInternship, company: e.target.value })}
          />
          <input
            type="text"
            placeholder="Link"
            value={newInternship.link}
            onChange={(e) => setNewInternship({ ...newInternship, link: e.target.value })}
          />
          <button onClick={handleAdd}>Add</button>
        </div>
      )}

      <ul className="internship-list">
        {internships.map((item, index) => (
          <li key={index} className="internship-card">
            <div>
              <p><strong>{item.title}</strong> at <em>{item.company}</em></p>
              <a href={item.link} target="_blank" rel="noopener noreferrer">Apply</a>
            </div>

            {(isAdmin || isHR) && (
              <div>
                <button
                  onClick={() => {
                    const updatedTitle = prompt("Update Title:", item.title);
                    const updatedCompany = prompt("Update Company:", item.company);
                    const updatedLink = prompt("Update Link:", item.link);
                    if (updatedTitle && updatedCompany && updatedLink) {
                      handleEdit(index, {
                        title: updatedTitle,
                        company: updatedCompany,
                        link: updatedLink,
                      });
                    }
                  }}
                >
                  Edit
                </button>
                <button onClick={() => handleDelete(index)}>Delete</button>
              </div>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}
